### Steps to reproduce

1. run the attached test. 


### Expected results

When the user changes the `Primary:`  TextField and taps on save the `SubFormField.state` changes to reflect the new location.

Inherently i expect that a custom implementation of FormField behaves like a TextFormField

### Actual results

The state doesnt change. See the test group `FormField<Location>`.


### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  testWidgets('change field_1', (WidgetTester tester) async {
    //Setup
    final form = SubFormField();
    const newValue = 'the new value the field should be set to';

    await tester.pumpWidget(MaterialApp(home: Scaffold(body: form)));

    // Enter some text in the TextFormField inside FormField<Location>
    await tester.enterText(find.byKey(const Key("field_1")), newValue);

    // Submit the form
    await tester.tap(find.text('save'));
    await tester.pump();


    // Verify that the state map is updated accordingly
    expect(form.state['field_1'], equals(newValue));
  });

  group("FormField<Location>", () {

    testWidgets('change location.primary', (WidgetTester tester) async {
      //Setup
      final form = SubFormField();
      const newValue = 'the new value the field should be set to';

      await tester.pumpWidget(MaterialApp(home: Scaffold(body: form)));

      // Enter some text in the TextFormField inside FormField<Location>
      await tester.enterText(find.byKey(const Key("primary")), newValue);

      // Submit the form
      await tester.tap(find.text('save'));
      await tester.pump();


      // Verify that the state map is updated accordingly
      expect(form.state['location'].primary, equals(newValue));
    });

    testWidgets('change location.sub', (WidgetTester tester) async {
      final form = SubFormField();
      const newValue = 'the new value the field should be set to';

      await tester.pumpWidget(MaterialApp(home: Scaffold(body: form)));

      final formField = find.byType(FormField<Location>);

      final subField = find.descendant(
        of: formField,
        matching: find.byType(TextFormField),
      ).at(1);


      // Enter some text in the TextFormField inside FormField<Location>
      await tester.enterText(subField, newValue);

      // Submit the form
      await tester.tap(find.text('save'));
      await tester.pump();


      // Verify that the state map is updated accordingly
      expect(form.state['location'], isNotNull);
      expect(form.state['location'].primary, equals(form.initialLocation.primary));
      expect(form.state['location'].sub, equals(newValue));
    });
  });
}


class Location{
  Location({required this.primary,required this.sub});

  final String primary;
  final String sub;

  Location copyWith({String? primary, String? sub}) => Location(primary: primary ?? this.primary,sub: sub ?? this.sub);

  @override
  toString() => "Location(primary: $primary, sub; $sub)";
}

class SubFormField extends StatelessWidget {
  SubFormField({super.key, Location? initialLocation})
      : state = {},
        initialLocation = initialLocation ??
            Location(primary: "1600 Pennsylvania Avenue NW, Washington, DC 20500, USA", sub: "Oval office");

  final Map<String, dynamic> state;

  final GlobalKey<FormState> _formKey = GlobalKey();
  final Location initialLocation;

  _sendSave() {
    if (_formKey.currentState!.validate()) {
      print("state didnt validate");
    }

    _formKey.currentState!.save();
    print(state);
  }

  @override
  Widget build(BuildContext context) {
    return Form(
      key: _formKey,
      child: Column(
        children: [
          TextFormField(
            key: const Key("field_1"),
            initialValue: "this one changes",
            onSaved: (v) => state["field_1"] = v,
          ),
          FormField<Location>(
            initialValue: initialLocation,
            onSaved: (v) => state["location"] = v,
            builder: (state) {
              if (state.value == null) {
                return const CircularProgressIndicator();
              }

              final location = state.value!;
              return ListTile(
                leading: const Icon(Icons.place),
                title: TextFormField(
                  key: const Key("primary"),
                  initialValue: location.primary,
                  decoration: const InputDecoration(labelText: "Primary:"),
                  validator: (val) => val == "" ? "cannot be empty" : null,
                  onSaved: (value) => state.didChange(location.copyWith(primary: value!)),
                ),
                subtitle: TextFormField(
                  key: const Key("sub"),
                  initialValue: location.sub,
                  decoration: const InputDecoration(labelText: "Sub:"),
                  onSaved: (value) => state.didChange(location.copyWith(sub: value)),
                ),
              );
            },
          ),
          ElevatedButton(onPressed: () => _sendSave(), child: const Text("save"))
        ],
      ),
    );
  }
}
```

