`TextField`s scroll into focus properly when the containing scrollview is a direct child of a `Scaffold`. However, if you push on a new screen, a new `Scaffold` is needed in order for the `TextField`s to scroll into focus in the newly pushed class. I would think that so long as a `Scaffold` is in the hierarchy that I should be able to push on new screens with scrollable `TextField`s without wrapping the new screen in a `Scaffold`. The below example will scroll textfields into focus properly on the first page, but when pushing on a new screen  by tapping the `FloatingActionButton`, the `TextField`s will not scroll.

```dart
import 'package:flutter/material.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'TextField Scroll Demo',
      home: MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  MyHomePage({Key key, this.title}) : super(key: key);

  final String title;

  @override
  _MyHomePageState createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('TextField Scroll Demo'),
      ),
      body: Form(
        child: ListView.builder(
            itemCount: 20,
            itemBuilder: (context, index) {
              return TextFormField(initialValue: index.toString());
            }),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: () {
          Navigator.push(
            context,
            MaterialPageRoute(
                builder: (context) {
                  return NewPage();
                }),
          );
        },
      ),
    );
  }
}

// Won't scroll without a new Scaffold
class NewPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Material(
      child: Form(
        child: ListView.builder(
            itemCount: 20,
            itemBuilder: (context, index) {
              return TextFormField(initialValue: index.toString());
            }),
      ),
    );
  }
}
```

