### Steps to reproduce

Run the code provided on android and ios, oldValue.selection.baseOffset return different values for both platforms when pressing backspace and deleting letters.

Reproducible on v3.0.4 as well.

### Expected results

oldValue.selection.baseOffset should match the length of the old word when deleting from the end of the word

### Actual results

oldValue.selection.baseOffset on iOS does not match the length of the old word but matches the length of the new word.

### Code sample

<details><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  // This widget is the root of your application.
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});
  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: TextField(
          inputFormatters: [OffsetInputFormatterTester()],
        ),
      ),
    );
  }
}

class OffsetInputFormatterTester extends TextInputFormatter {
  @override
  TextEditingValue formatEditUpdate(
    TextEditingValue oldValue,
    TextEditingValue newValue,
  ) {
    print('new length ${newValue.text.length}');
    print('old length ${oldValue.text.length}');
    print('new offset${newValue.selection.baseOffset}');
    print('old offset ${oldValue.selection.baseOffset}');
    print('===============');

    return TextEditingValue(
      text: newValue.text,
      selection:
          TextSelection.collapsed(offset: newValue.selection.base.offset),
    );
  }
}

